+        assert_eq!(summary.bocpd_delay_ms, Some(50));
+        assert_eq!(summary.history_len(), 1);
+        assert_eq!(
+            summary.recent_resizes.back().unwrap().bocpd_p_burst,
+            Some(0.85)
+        );
+    }
